# Frontend Style Guide — Sem Parar (Zustand-only + Hook Component Pattern)

Welcome to the **Sem Parar Frontend Style Guide**.  
This version consolidates: **Zustand as the only state manager**, **Hook Component pattern** for Screens and Atomic components, **services architecture (SOLID)**, and an **cache pattern**.

> Sit down, have a cup of coffee and read this calmly. ☕

---

## :pushpin: Table of Contents

- [Introduction](#introduction)
- [Components & Screens — Hook Component Pattern](#components--screens--hook-component-pattern)
- [Atomic Components — Hook Component Pattern](#atomic-components--hook-component-pattern)
- [Project Organization](#project-organization)
- [Services Architecture](#services-architecture)
- [State Management (Zustand-only)](#state-management-zustand-only)
- [Routes Naming](#routes-naming)
- [Folder Naming Rules](#folder-naming-rules)
- [Code Standards](#code-standards)
- [Styles Patterns](#styles-patterns)
- [Cache Pattern](#cache-pattern)
- [Checklist](#checklist)

---

## Introduction

The goal of this guide is to ensure **consistency, testability and scalability** across our frontend projects.

Key decisions:

- **Zustand** is the **exclusive** global/shared state manager.
- UI follows the **Hook Component** pattern (logic hook + dumb view).
- Domain logic lives in **`/services`** with **SOLID** layering.
- Cache is **typed and reusable**.

---

## Components & Screens — Hook Component Pattern

Each screen is split into a logic hook and a render-only component.

```
screens/Home/
├── index.ts        # logic: export useHomeScreen()
├── view.tsx        # render: export default HomeScreen
└── Models/
    └── index.d.ts    # types (Props, State, Handlers, Return)
```

**Models/index.d.ts**

```ts
export interface HomeParams {
  welcome?: string;
}
export interface HomeState {
  greeting: string;
  isLoading: boolean;
}
export interface HomeHandlers {
  onPressCTA: () => void;
}
export type UseHomeReturn = HomeState & HomeHandlers;
```

**index.ts (logic hook)**

```ts
import { useCallback, useMemo, useState, useEffect } from 'react';
import type { HomeParams, UseHomeReturn } from './Models';
import { useUserStore } from '@/services/user/store'; // Zustand slice example

export function useHomeScreen(params?: HomeParams): UseHomeReturn {
  const name = useUserStore(s => s.name);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const t = setTimeout(() => setIsLoading(false), 300);
    return () => clearTimeout(t);
  }, []);

  const greeting = useMemo(
    () => params?.welcome ?? `Hello, ${name || 'guest'}!`,
    [
      params?.welcome,
      name,
    ],
  );

  const onPressCTA = useCallback(() => {
    // Call services, analytics, navigation, etc.
  }, []);

  return {
    greeting,
    isLoading,
    onPressCTA,
  };
}
```

**view.tsx (render)**

```tsx
import React from 'react';
import { View } from 'react-native';
import { Text, Button } from '@semparar/design-system-app';
import { useHomeScreen } from './index';
import type { HomeParams } from './Models';

type Props = HomeParams;

export default function HomeScreen(props: Props) {
  const { greeting, isLoading, onPressCTA } = useHomeScreen(props);

  if (isLoading) {
    return (
      <View>
        <Text>Loading...</Text>
      </View>
    );
  }

  return (
    <View>
      <Text>{greeting}</Text>
      <Button onPress={onPressCTA} text="Continue" />
    </View>
  );
}
```

---

## Atomic Components — Hook Component Pattern

```
atomic/atoms/Button/
├── index.ts        # logic: export useButton()
├── view.tsx        # render: export default Button
└── Models/
    └── index.d.ts
```

**Models/index.d.ts**

```ts
export interface ButtonProps {
  text: string;
  disabled?: boolean;
  onPress?: () => void;
}
export interface ButtonState {
  pressed: boolean;
}
export interface ButtonHandlers {
  handlePress: () => void;
}
export type UseButtonReturn = ButtonState & ButtonHandlers;
```

**index.ts (logic hook)**

```ts
import { useCallback, useState } from 'react';
import type { ButtonProps, UseButtonReturn } from './Models';

export function useButton(props: ButtonProps): UseButtonReturn {
  const [pressed, setPressed] = useState(false);

  const handlePress = useCallback(() => {
    setPressed(true);
    props.onPress?.();
    setTimeout(() => setPressed(false), 150);
  }, [props.onPress]);

  return {
    pressed,
    handlePress,
  };
}
```

**view.tsx (render)**

```tsx
import React from 'react';
import { Pressable, View } from 'react-native';
import { Text } from '@semparar/design-system-app';
import { useButton } from './index';
import type { ButtonProps } from './Models';

export default function Button(props: ButtonProps) {
  const { pressed, handlePress } = useButton(props);

  return (
    <Pressable disabled={props.disabled} onPress={handlePress}>
      <View>
        <Text>
          {props.text}
          {pressed ? ' •' : ''}
        </Text>
      </View>
    </Pressable>
  );
}
```

---

## Project Organization

```
src/
├── @types/            # Global TS types
├── assets/            # Images, fonts, icons
├── atomic/            # UI components (Hook Component pattern)
│   ├── atoms/
│   ├── molecules/
│   └── organisms/
├── modules/           # Microfrontends shared and native modules
├── screens/           # Page-level (Hook Component pattern)
├── services/          # Domain logic (SOLID layout)
│   ├── api/           # HTTP layer (Axios/Fetch)
│   ├── class/         # Class with logical requests
│   ├── hooks/         # Specific service hooks
│   ├── repository/    # Data abstraction & mapping
│   ├── services/      # Business orchestration
│   ├── storage/       # Storage orchestration with cache or not
│   ├── store/         # Zustand slices (only)
│   ├── models/        # Domain types & contracts
│   ├── utils/         # Reusable service helps
│   └── index.ts       # Public exports
├── hooks/             # Cross-cutting React hooks
├── routes/            # Navigation config
├── settings/          # Env & global config (axios, etc.)
└── utils/             # General-purpose helpers
```

> UI **never** calls API directly. All effects & side effects live in the **logic hooks** (which call `/services`).

---

## Services Architecture

**Flow:** `UI → services → repository → api` and `UI → services → store (Zustand)`

- **api/**: request clients; no domain logic.
- **class/**: class with logical requests.
- **hooks/**: specific service hooks.
- **repository/**: maps transport to domain, aggregates sources.
- **services/**: orchestration and business rules.
- **storage/**: storage orchestration with cache or not.
- **store/**: Zustand slices (single source of app state).
- **models/**: types, DTOs, contracts.
- **utils/**: reusable service helpers.

Principles:

- Single responsibility per folder/file.
- No circular dependencies.
- Public APIs exported via `services/index.ts` per domain.

---

## State Management (Zustand-only)

- All global/shared state is **Zustand**.
- Slices live under `/services/<domain>/store/`.
- Use `persist` (with `createJSONStorage`) only when needed.
- Keep setters pure; side effects go in hooks or services.

**Slice example**

```ts
import type { StateCreator } from 'zustand';
import type { AuthActions, AuthState } from '../models/store';

export type AuthSlice = {
  auth: AuthState;
  authActions: AuthActions;
};

const initialAuth = {
  user: null,
  loading: false,
  error: undefined,
};

export const createAuthSlice: StateCreator<
  AuthSlice,
  [],
  [],
  AuthSlice
> = set => ({
  auth: initialAuth,
  authActions: {
    setLoading: v =>
      set(s => ({
        auth: {
          ...s.auth,
          isLoading: v,
        },
      })),
    setUser: v =>
      set(s => ({
        auth: {
          ...s.auth,
          user: v,
        },
      })),
    setError: v =>
      set(s => ({
        auth: {
          ...s.auth,
          error: v,
        },
      })),
    reset: () => set({ auth: initialAuth }),
  },
});
```

**Root Store**

- Applies to ALL Sem Parar frontend apps — including SuperApp.

```ts
import { create } from 'zustand';
import { devtools, persist, createJSONStorage } from 'zustand/middleware';
import { immer } from 'zustand/middleware/immer';

import {
  createUserSlice,
  type UserSlice,
} from '@semparar/mf-app-user/src/newArch/user';
import { createAuthSlice, type AuthSlice } from '@semparar/mf-app-yourmf';

import storage from '~/redux/store/storage';

/** Add your slice Type */
export type RootStore = UserSlice & AuthSlice;

export const useRootStore = create<RootStore>()(
  devtools(
    persist(
      immer((...a) => ({
        ...createUserSlice(...a),
        ...createAuthSlice(...a), // Add your slice here
      })),
      {
        name: 'root-storage',
        storage: createJSONStorage(() => storage),
        partialize: s => ({
          user: s.user,
          auth: s.auth, // Add your store data
        }),
        merge: (persisted, current) => ({
          ...current,
          ...(persisted as Partial<RootStore>),
        }),
      },
    ),
    { name: 'RootStore' },
  ),
);
```

- For Use on Class.

```ts
class Auth {
  private readonly setAuth;

  constructor () {
    this.setUser = useRootStore.getState().authActions.setUser;
  }

  function doSomething(data) {
    this.setUser({ ...data });
  }
}
```

- For Use on Component/Screen.
- UI never imports the store directly — uses selectors

```ts
const loading = useRootStore(s => s.user.isLoading);
const token = useRootStore(s => s.auth.token);
```

---

## Routes Naming

Standardize as **`Acronym + Route`**:

- ✅ `SPPayment` (Sem Parar Payment)
- ✅ `FTHPayment` (Fintech Payment)

---

## Folder Naming Rules

| Folder                              | Convention   | Examples                   |
| ----------------------------------- | ------------ | -------------------------- |
| `atomic`, `screens`, `routes`       | `PascalCase` | `HomeScreen`, `CarDetails` |
| `assets`, `hooks`, `services`, etc. | `camelCase`  | `useAuth`, `authService`   |

---

## Code Standards

**Language**: English only.  
**Naming**: `camelCase` (vars/functions), `PascalCase` (components/classes), `UPPER_SNAKE_CASE` (constants).

**Explanatory variables**

```js
const onlyNumbersRegex = /^\d+$/;
const getNumberValidation = message => value =>
  !onlyNumbersRegex.test(value) && message;
const isNumber = getNumberValidation('error message');
isNumber(1);
```

**Semantic constants**

```js
const DAY_IN_MILLISECONDS = 86400000;
setTimeout(doSomething, DAY_IN_MILLISECONDS);
```

**Library workarounds with link**

```js
// Refer to issue https://github.com/ngokevin/react-file-reader-input/issues/11#issuecomment-363484861
// eslint-disable-next-line no-param-reassign
event.target.value = '';
```

**JSDoc**

```js
/**
 * Truncates an event name to the max length.
 * @param {*} eventName
 * @param {*} maxLength
 */
```

**Hooks: multi-line deps & IIFE**

```ts
useEffect(() => {
  (async () => {
    await CustomMath.randomSum();
    setSum(42);
  })();
}, [setSum]);
```

**Extract conditions**

```ts
const hasSelectedOffer = !!(selectedProduct || selectedLeasingOffer);
if (!hasSelectedOffer && !individualOffer) return;
```

**Optional chaining**

```ts
const answers = formikForm?.values?.answers;
```

**JSX indentation**

```tsx
{
  !isEnd && <Button text="CTA" onPress={handleNavigate} />;
}
```

**Early returns**

```ts
if (!data) return null;
return <View />;
```

**Nullish coalescing**

```ts
return data ?? 0;
```

---

## Styles Patterns

- Do **not** use `StyleSheet` or `styled-components`.
- Use **@semparar/design-system-app** for components, tokens, and theming.

---

## Cache Pattern

Keep cache typed, serializable, and domain.

```ts
import storage from '~/redux/store/storage';

export interface CachedData<T> {
  timestamp: number;
  data: T;
}

export interface StorageContract<T> {
  get(): Promise<CachedData<T> | null>;
  save(data: T): Promise<void>;
  remove(): Promise<void>;
}

export class GenericStorage<T> implements StorageContract<T> {
  constructor(private readonly key: string) {}

  async get(): Promise<CachedData<T> | null> {
    const json = await storage.getItem(this.key);
    if (!json) return null;
    return JSON.parse(json) as CachedData<T>;
  }

  async save(data: T): Promise<void> {
    const payload: CachedData<T> = {
      timestamp: Date.now(),
      data,
    };
    await storage.setItem(this.key, JSON.stringify(payload));
  }

  async remove(): Promise<void> {
    await storage.removeItem(this.key);
  }
}
```

**Guidelines**

- One storage class per module/feature.
- Types/interfaces live in `Models/` where appropriate.
- Use `timestamp` for freshness/expiry strategies.
- Never persist secrets/PII outside secure storage.
- Keep payloads small and JSON-serializable.

---

## Checklist

- [ ] Screens/Components follow **Hook Component pattern** (`index.ts` hook + `view.tsx` render)
- [ ] Types live in **Models/**
- [ ] Only **Zustand** for global/shared state under **/services/<domain>/store/**
- [ ] UI never calls API directly (go through **/services**)
- [ ] Code standards and styles patterns applied
- [ ] Cache implemented via **GenericStorage** (when needed)
- [ ] Routes and folder naming conventions followed

---

Happy shipping! 🚀

# Claude Code Migration Hallucinations - Analysis and Fix Plan

Last Updated: 2026-01-29
Status: ANALYSIS COMPLETE - AWAITING IMPLEMENTATION

================================================================================
EXECUTIVE SUMMARY
================================================================================

During the Redux to Zustand migration, Claude Code committed several
"hallucinations" - fabricated logic changes that deviate from the original
production code. This document catalogs each issue, explains the root cause,
and provides a fix plan.

CRITICAL RULE: All logic must be maintained exactly as it was in production.
The code passed QA for each feature - only infrastructure changes (Redux→Zustand)
should have been made, NOT logic changes.

================================================================================
ROOT CAUSE: TWO SEPARATE SYSTEMS WERE CONFLATED
================================================================================

In the source repository (card-place), there were **TWO SEPARATE systems**
that serve **DIFFERENT purposes**:

### SYSTEM 1: newArch Zustand (Already existed - for FAQ display)
- Endpoint: /fintech/v1/rewardProgram/consult-parameter
- Category searched: 'saiba mais' (case-insensitive)
- Purpose: Fetch FAQ questions/answers for LearnMoreRewardProgram screen
- Repository: mapParameterPointsProgramResponse() extracts FAQ data
- Consumer: LearnMoreRewardProgram screen → displays accordion with Q&A

### SYSTEM 2: Redux Saga (Was supposed to be migrated - for pointsQuantity)
- Endpoint: products/v1/pointsProgram/consult-fintech-parameter-points-program
- Category searched: 'pointsRescueSentence' (exact match)
- Purpose: Fetch pointsQuantity for InvoiceCashback rescue calculations
- Logic: extractPointsQuantity() parses JSON from value field
- Consumers: InvoiceCashbackOnboarding, InvoiceCashbackPoints screens

### WHAT CLAUDE CODE DID WRONG:
1. Copied the newArch Zustand code (System 1) to the new repository
2. Assumed this replaced the Redux saga (System 2)
3. LOST System 2 completely - no endpoint, no extraction, pointsQuantity always 0

### WHAT SHOULD HAVE BEEN DONE:
Both systems should coexist:
- System 1 for FAQ display (LearnMoreRewardProgram)
- System 2 for pointsQuantity calculation (InvoiceCashback screens)

USER CONFIRMATION: Both endpoints exist and both are needed.

================================================================================
SOURCE REPOSITORIES ANALYZED
================================================================================

1. SOURCE (card-place): ../rnm-app-fintech-card-place
   - Redux code: src/redux/ducks/ and src/redux/sagas/
   - Existing Zustand: src/newArch/store/rewardProgram/

2. TARGET (rewardprogram): Current repository
   - Migrated Zustand: src/services/

================================================================================
HALLUCINATION #1: MISSING pointsQuantity EXTRACTION (CRITICAL)
================================================================================

SEVERITY: CRITICAL - Feature broken in production
LOCATION: src/services/services/parameter.service.ts

ORIGINAL BEHAVIOR (Redux saga parameterization.ts):
```javascript
function extractPointsQuantity(parameterization: ParametrizationData[]): number {
  const pointsRescueItem = parameterization?.find(
    item => item.category === 'pointsRescueSentence'
  );

  if (!pointsRescueItem?.value) {
    return 0;
  }

  try {
    let parsedValue = JSON.parse(pointsRescueItem.value);
    if (typeof parsedValue === 'string') {
      parsedValue = JSON.parse(parsedValue);
    }
    if (parsedValue && parsedValue.pointsQuantity !== undefined) {
      const ptsQuantity = Number(parsedValue.pointsQuantity);
      if (!isNaN(ptsQuantity) && ptsQuantity >= 0) {
        return ptsQuantity;
      }
    }
    return 0;
  } catch (error) {
    console.error('Error parsing pointsQuantity:', error);
    return 0;
  }
}
```

The saga extracted `pointsQuantity` from the API response and dispatched it
to the Redux store via `successParameterization(parameterizationData, pointsQuantity)`.

MIGRATED BEHAVIOR (WRONG):
- parameter.service.ts calls `mapParameterPointsProgramResponse()` which only
  extracts FAQ data (for "saiba mais" category), NOT pointsQuantity
- `setPointsQuantity` action exists in store but is NEVER called
- pointsQuantity is always 0

IMPACT:
- InvoiceCashbackOnboarding: Shows "Cada 0 pontos valem R$ 0,00"
- InvoiceCashbackPoints: Conversion calculations return 0
- All rescue flow calculations are broken

ROOT CAUSE:
The existing newArch code was for a DIFFERENT purpose (FAQ display) using a
different endpoint. Claude Code copied this code without understanding that
the Redux saga had ADDITIONAL functionality (pointsQuantity extraction) that
was not present in the newArch Zustand code.

FIX REQUIRED:
Add pointsQuantity extraction to parameter.service.ts after successful API call.
Must extract from 'pointsRescueSentence' category, NOT 'saiba mais'.

================================================================================
HALLUCINATION #2: DIFFERENT API ENDPOINT FOR PARAMETERIZATION
================================================================================

SEVERITY: HIGH - May cause wrong data to be fetched
LOCATION: src/services/api/parameter.api.ts

ORIGINAL ENDPOINT (Redux saga):
  'products/v1/pointsProgram/consult-fintech-parameter-points-program'

MIGRATED ENDPOINT (WRONG):
  '/fintech/v1/rewardProgram/consult-parameter'

ANALYSIS:
USER CONFIRMED: These are different endpoints. Must revert to original.

The newArch code used '/fintech/v1/rewardProgram/consult-parameter' for FAQ
data, but the Redux saga used a different endpoint for pointsQuantity.
These serve different purposes and the original endpoint must be restored.

FIX REQUIRED (CONFIRMED BY USER):
Revert to original endpoint: 'products/v1/pointsProgram/consult-fintech-parameter-points-program'
Also need to update response handling to match original structure:
- Original: response.data.serviceMessage.codigoRetorno and response.data.data
- Current: response.status and response.data[]

================================================================================
HALLUCINATION #3: RESCUE SERVICE - RESPONSE VALIDATION LOGIC CHANGED
================================================================================

SEVERITY: MEDIUM - May cause incorrect success/failure detection
LOCATION: src/services/services/rescue.service.ts:24-27

ORIGINAL LOGIC (Redux saga rescue/index.ts):
```javascript
const rawStatus =
  response?.data?.status ??
  response?.data?.data?.status
```
Order: Check response.data.status FIRST, then response.data.data.status

MIGRATED LOGIC (WRONG):
```javascript
const rawStatus = (response?.status ?? response?.data?.status) as
  | { message: string }
  | undefined;
```
Order: Check response.status FIRST (HTTP response object), then response.data.status

IMPACT:
- Original checks nested data structure first (API response body)
- Migrated checks HTTP status object first (wrong level)
- May cause incorrect success/failure detection

FIX REQUIRED:
Change to:
```javascript
const rawStatus = response?.data?.status ?? response?.data?.data?.status;
```

================================================================================
HALLUCINATION #4: PRODUCTS API - ADDED UNEXPECTED participantId HEADER
================================================================================

SEVERITY: LOW - May not cause issues but is a logic change
LOCATION: src/services/api/products.api.ts:10-13

ORIGINAL (Redux saga products.ts):
```javascript
const response = yield call(api.get, '/fintech/v1/rewardProgram/product', {});
```
No participantId header was passed.

MIGRATED (ADDED):
```javascript
const response = await api.get<PointsProductsApiResponse>(
  `/fintech/v1/rewardProgram/product`,
  {
    headers: {
      ...(participantId && { participantId }),
    },
  },
);
```
Adds participantId header that didn't exist in original.

IMPACT:
- May cause different API behavior if backend uses this header
- Logic change that wasn't requested

FIX REQUIRED:
Remove participantId header to match original behavior:
```javascript
async getProducts(): Promise<PointsProductsApiResponse> {
  const response = await api.get<PointsProductsApiResponse>(
    `/fintech/v1/rewardProgram/product`,
    {},
  );
  return response.data;
}
```

================================================================================
HALLUCINATION #5: PRODUCTS SERVICE - MISSING shouldFetch SUCCESS GUARD
================================================================================

SEVERITY: LOW - Performance issue, not functional
LOCATION: src/services/services/products.service.ts:7-10

ORIGINAL BEHAVIOR:
Redux had no explicit caching - would always fetch on action dispatch.

MIGRATED BEHAVIOR:
```javascript
function shouldFetchProducts(): boolean {
  const { pointsProducts } = useRootStore.getState();
  return pointsProducts.status !== PointsProductsStatus.LOADING;
}
```
Only checks LOADING status, not SUCCESS.

ISSUE:
This allows refetching even when data is already SUCCESS (cached).
While this matches original Redux behavior, the newArch extract.service.ts
pattern checks both:
```javascript
return (
  status !== PointsExtractStatus.LOADING &&
  status !== PointsExtractStatus.SUCCESS
);
```

FIX REQUIRED:
KEEP AS-IS - This matches original Redux behavior.
Document this as an intentional difference from newArch pattern.

================================================================================
HALLUCINATION #6: DUPLICATE ANALYTICS EVENTS
================================================================================

SEVERITY: LOW - Analytics noise
LOCATION: src/services/services/products.service.ts:36,51 and 53,56

ORIGINAL (Redux saga products.ts):
Had duplicate eventServerResponse calls (lines 29-36, 51-57, 59-66, etc.)
This was a pre-existing bug in the original code.

MIGRATED:
Also has duplicate calls (lines 36+51, 53+56)

FIX REQUIRED:
KEEP AS-IS - This duplicates the original behavior (even if buggy).
Document as pre-existing issue, do not fix during migration.

================================================================================
OBSERVATIONS (NOT HALLUCINATIONS - INTENTIONAL PATTERNS)
================================================================================

1. ANALYTICS_EVENTS constant structure matches original saga objects exactly
   - PRODUCTS_SUCCESS, PRODUCTS_ERROR, BALANCE_SUCCESS, BALANCE_ERROR all correct

2. extractConversionFactor and findInvoiceProduct in repository match original saga logic
   - Loop through products for convertionFactor
   - Find product with name/action containing 'fatura'

3. conversionFactor is being set correctly via two sources:
   - First from extractConversionFactor (any product with convertionFactor)
   - Then overwritten if invoiceProduct has conversionFactor

4. Marketplace service logic matches original saga exactly
   - Same endpoint, same success check (codigoRetorno === 0)

================================================================================
FIX PRIORITY ORDER
================================================================================

PRIORITY 1 - CRITICAL (Feature broken):
[ ] Fix #0: Revert parameter API endpoint (CONFIRMED BY USER)
[ ] Fix #1: Add pointsQuantity extraction to parameter.service.ts
[ ] Fix #1b: Update parameter.model.ts with original response types

PRIORITY 2 - HIGH (Logic changed):
[ ] Fix #3: Fix rescue response validation order

PRIORITY 3 - MEDIUM (Logic added):
[ ] Fix #4: Remove participantId header from products API

================================================================================
IMPLEMENTATION PLAN
================================================================================

PHASE 0: Revert Parameter API Endpoint (HIGH - CONFIRMED BY USER)

File: src/services/api/parameter.api.ts

Change from:
```typescript
return api.get<ParameterPointsProgramResponse[]>(
  '/fintech/v1/rewardProgram/consult-parameter'
);
```

To:
```typescript
return api.get<ParameterizationResponse>(
  'products/v1/pointsProgram/consult-fintech-parameter-points-program'
);
```

File: src/services/models/parameter.model.ts

Add interfaces to match original response:
```typescript
export interface ParameterizationResponse {
  data: {
    serviceMessage: {
      codigoRetorno: number;
      mensagem: string;
    };
    error: {};
    status: {
      sessionId: string;
    };
    data: ParametrizationData[];
  };
}

export interface ParametrizationData {
  category: string;
  value: string;
  dateCreated: string | Date;
  PK: string;
  dateUpdated: string | Date;
  status: number;
}
```

--------------------------------------------------------------------------------

PHASE 1: Fix pointsQuantity extraction (CRITICAL)

File: src/services/services/parameter.service.ts

Rewrite service to match original saga logic:

```typescript
export async function getParameterPointsProgram(): Promise<void> {
  const { parameterPointsProgramActions, parameterPointsProgram } =
    useRootStore.getState();

  if (
    parameterPointsProgram.status === ParameterPointsProgramStatus.LOADING ||
    parameterPointsProgram.status === ParameterPointsProgramStatus.SUCCESS
  ) {
    return;
  }

  try {
    parameterPointsProgramActions.setStatus(ParameterPointsProgramStatus.LOADING);

    const response = await getParameterPointsProgramApi();

    // Match original saga logic exactly
    const returnCode = response?.data?.serviceMessage?.codigoRetorno;
    const parameterizationData = response?.data?.data;

    if (returnCode === 0 && parameterizationData) {
      const pointsQuantity = extractPointsQuantity(parameterizationData);
      parameterPointsProgramActions.setData(parameterizationData);
      parameterPointsProgramActions.setPointsQuantity(pointsQuantity);
      return;
    }

    parameterPointsProgramActions.setStatus(ParameterPointsProgramStatus.ERROR);
  } catch {
    parameterPointsProgramActions.setStatus(ParameterPointsProgramStatus.ERROR);
  }
}
```

Add extractPointsQuantity function (matching original saga exactly):

```typescript
function extractPointsQuantity(parameterization: ParametrizationData[]): number {
  const pointsRescueItem = parameterization?.find(
    item => item.category === 'pointsRescueSentence'
  );

  if (!pointsRescueItem?.value) {
    return 0;
  }

  try {
    let parsedValue = JSON.parse(pointsRescueItem.value);
    if (typeof parsedValue === 'string') {
      parsedValue = JSON.parse(parsedValue);
    }
    if (parsedValue && parsedValue.pointsQuantity !== undefined) {
      const ptsQuantity = Number(parsedValue.pointsQuantity);
      if (!isNaN(ptsQuantity) && ptsQuantity >= 0) {
        return ptsQuantity;
      }
    }
    return 0;
  } catch (error) {
    console.error('Error parsing pointsQuantity:', error);
    return 0;
  }
}
