import { PointsActions } from '../../ducks/points';
import { ParameterizationResponse, ParametrizationData } from './models';

function extractPointsQuantity(parameterization: ParametrizationData[]): number {
  const pointsRescueItem = parameterization?.find(
    item => item.category === 'pointsRescueSentence'
  );

  if (!pointsRescueItem?.value) {
    return 0;
  }

  try {
    let parsedValue = JSON.parse(pointsRescueItem.value);

    if (typeof parsedValue === 'string') {
      parsedValue = JSON.parse(parsedValue);
    }

    if (parsedValue && parsedValue.pointsQuantity !== undefined) {
      const ptsQuantity = Number(parsedValue.pointsQuantity);

      if (!isNaN(ptsQuantity) && ptsQuantity >= 0) {
        return ptsQuantity;
      }
    }

    return 0;
  } catch (error) {
    console.error('Error parsing pointsQuantity:', error);
    return 0;
  }
}

export function* getParameterization() {
  try {
    const response: ParameterizationResponse = yield call(
      api.get,
      'products/v1/pointsProgram/consult-fintech-parameter-points-program',
    );

    const returnCode = response?.data?.serviceMessage?.codigoRetorno;
    const parameterizationData = response?.data?.data;

    if (returnCode === 0) {
      const pointsQuantity = extractPointsQuantity(parameterizationData);

      yield put(PointsActions.successParameterization(
        parameterizationData,
        pointsQuantity,
      ));
    } else {
      yield put(PointsActions.failedParameterization());
    }
  } catch(err) {
    yield put(PointsActions.failedParameterization());
  }
}

